export interface InvoiceItem {
  description: string;
  quantity: number;
  unitPrice: number;
  total: number;
}

export interface InvoiceData {
  invoiceNumber: string;
  date: string;
  dueDate?: string;
  vendorName: string;
  vendorAddress: string;
  vendorPhone?: string;
  customerName: string;
  customerAddress?: string;
  items: InvoiceItem[];
  subtotal: number;
  taxAmount: number;
  totalAmount: number;
  currency: string;
  paymentStatus?: string;
}

export type ExtractionStatus = 'idle' | 'processing' | 'success' | 'error';

export interface FileInfo {
  name: string;
  size: string;
  type: string;
  previewUrl?: string;
  content?: string; // For text files
}

import { GoogleGenAI, Type } from "@google/genai";
import { InvoiceData } from "../types";

const INVOICE_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    invoiceNumber: { type: Type.STRING, description: "Unique identifier for the invoice" },
    date: { type: Type.STRING, description: "Issue date of the invoice" },
    dueDate: { type: Type.STRING, description: "Due date for payment" },
    vendorName: { type: Type.STRING, description: "Name of the seller or company providing the service" },
    vendorAddress: { type: Type.STRING, description: "Full address of the vendor" },
    vendorPhone: { type: Type.STRING, description: "Contact phone of the vendor" },
    customerName: { type: Type.STRING, description: "Name of the buyer or client" },
    customerAddress: { type: Type.STRING, description: "Address of the customer" },
    items: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING },
          quantity: { type: Type.NUMBER },
          unitPrice: { type: Type.NUMBER },
          total: { type: Type.NUMBER },
        },
        required: ["description", "total"],
      },
    },
    subtotal: { type: Type.NUMBER },
    taxAmount: { type: Type.NUMBER },
    totalAmount: { type: Type.NUMBER },
    currency: { type: Type.STRING, description: "Currency code (e.g., USD, EUR)" },
    paymentStatus: { type: Type.STRING, description: "Current status of payment if indicated" },
  },
  required: ["invoiceNumber", "vendorName", "totalAmount", "items"],
};

export const extractInvoiceData = async (
  fileData: string,
  mimeType: string,
  isText: boolean = false
): Promise<InvoiceData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `Act as an expert financial data extractor. Analyze the provided ${isText ? 'text' : 'document'} and extract all relevant invoice information accurately. Ensure numeric values are returned as numbers and dates are in a consistent YYYY-MM-DD format if possible.`;

  const config = {
    responseMimeType: "application/json",
    responseSchema: INVOICE_SCHEMA,
    temperature: 0.1, // Lower temperature for more consistent extraction
  };

  const model = "gemini-3-flash-preview";

  let response;

  if (isText) {
    response = await ai.models.generateContent({
      model,
      contents: `Context: ${prompt}\n\nInvoice Content:\n${fileData}`,
      config,
    });
  } else {
    response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType,
              data: fileData,
            },
          },
        ],
      },
      config,
    });
  }

  const resultText = response.text;
  if (!resultText) {
    throw new Error("Failed to extract data from the invoice.");
  }

  return JSON.parse(resultText) as InvoiceData;
};

import React, { useRef, useState } from 'react';
import { FileInfo } from '../types';

interface FileUploadProps {
  onFileSelect: (file: File, fileInfo: FileInfo) => void;
  isLoading: boolean;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, isLoading }) => {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = () => {
    setIsDragging(false);
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const processFile = async (file: File) => {
    const fileInfo: FileInfo = {
      name: file.name,
      size: formatFileSize(file.size),
      type: file.type,
    };

    if (file.type.startsWith('image/')) {
      fileInfo.previewUrl = URL.createObjectURL(file);
    } else if (file.type === 'text/plain') {
      const text = await file.text();
      fileInfo.content = text;
    }

    onFileSelect(file, fileInfo);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
  };

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      onClick={() => !isLoading && fileInputRef.current?.click()}
      className={`
        relative border-2 border-dashed rounded-2xl p-8 transition-all duration-300 cursor-pointer
        flex flex-col items-center justify-center min-h-[250px]
        ${isDragging ? 'border-indigo-500 bg-indigo-500/10 scale-[1.01]' : 'border-zinc-800 hover:border-zinc-600 bg-zinc-900/50'}
        ${isLoading ? 'opacity-50 cursor-not-allowed' : ''}
      `}
    >
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileInput}
        className="hidden"
        accept="application/pdf,image/*,text/plain"
        disabled={isLoading}
      />

      <div className="w-16 h-16 bg-zinc-800 rounded-full flex items-center justify-center mb-4 text-zinc-400 group-hover:text-indigo-400 transition-colors">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
        </svg>
      </div>

      <h3 className="text-xl font-semibold mb-2 text-white">Upload Invoice</h3>
      <p className="text-zinc-400 text-center max-w-sm">
        Drag and drop your PDF, image, or text file here, or click to browse.
      </p>
      <p className="mt-4 text-xs text-zinc-500">
        Supports PDF, JPG, PNG, and TXT (Max 10MB)
      </p>

      {isLoading && (
        <div className="absolute inset-0 bg-zinc-950/40 rounded-2xl flex flex-col items-center justify-center backdrop-blur-[2px]">
          <div className="w-8 h-8 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"></div>
          <span className="text-sm font-medium text-white">Extracting Data...</span>
        </div>
      )}
    </div>
  );
};

export default FileUpload;

import React, { useState } from 'react';

interface JsonDisplayProps {
  data: any;
}

const JsonDisplay: React.FC<JsonDisplayProps> = ({ data }) => {
  const [copied, setCopied] = useState(false);

  const copyToClipboard = () => {
    navigator.clipboard.writeText(JSON.stringify(data, null, 2));
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const downloadJson = () => {
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `invoice-data-${new Date().getTime()}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="bg-[#0f0f0f] rounded-xl overflow-hidden border border-zinc-800 flex flex-col h-full">
      <div className="flex items-center justify-between px-4 py-3 bg-zinc-900 border-b border-zinc-800">
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-red-500/80"></div>
          <div className="w-3 h-3 rounded-full bg-yellow-500/80"></div>
          <div className="w-3 h-3 rounded-full bg-green-500/80"></div>
          <span className="ml-2 text-xs font-medium text-zinc-400 uppercase tracking-wider">JSON Result</span>
        </div>
        <div className="flex gap-2">
          <button
            onClick={copyToClipboard}
            className="p-1.5 rounded bg-zinc-800 hover:bg-zinc-700 text-zinc-300 transition-colors flex items-center gap-1 text-xs"
            title="Copy to clipboard"
          >
            {copied ? (
              <>
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5 text-green-500" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                </svg>
                <span>Copied</span>
              </>
            ) : (
              <>
                <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                </svg>
                <span>Copy</span>
              </>
            )}
          </button>
          <button
            onClick={downloadJson}
            className="p-1.5 rounded bg-zinc-800 hover:bg-zinc-700 text-zinc-300 transition-colors flex items-center gap-1 text-xs"
            title="Download JSON"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-3.5 w-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
            <span>Download</span>
          </button>
        </div>
      </div>
      <div className="flex-grow p-6 overflow-auto mono text-sm leading-relaxed">
        <pre className="text-indigo-300">
          {JSON.stringify(data, null, 2)}
        </pre>
      </div>
    </div>
  );
};

export default JsonDisplay;

import React, { useState, useEffect } from 'react';
import { InvoiceData, ExtractionStatus, FileInfo } from './types';
import { extractInvoiceData } from './services/geminiService';
import FileUpload from './components/FileUpload';
import JsonDisplay from './components/JsonDisplay';
import InvoiceSummary from './components/InvoiceSummary';

const App: React.FC = () => {
  const [status, setStatus] = useState<ExtractionStatus>('idle');
  const [error, setError] = useState<string | null>(null);
  const [extractedData, setExtractedData] = useState<InvoiceData | null>(null);
  const [fileInfo, setFileInfo] = useState<FileInfo | null>(null);
  const [viewMode, setViewMode] = useState<'visual' | 'json'>('visual');

  const handleFileSelect = async (file: File, info: FileInfo) => {
    setStatus('processing');
    setError(null);
    setFileInfo(info);
    setExtractedData(null);

    try {
      let dataToProcess: string;
      const isText = file.type === 'text/plain';

      if (isText) {
        dataToProcess = await file.text();
      } else {
        // Convert to base64 for Gemini API
        dataToProcess = await new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.onload = () => {
            const result = reader.result as string;
            // Remove the "data:mime/type;base64," prefix
            resolve(result.split(',')[1]);
          };
          reader.onerror = reject;
          reader.readAsDataURL(file);
        });
      }

      const result = await extractInvoiceData(dataToProcess, file.type, isText);
      setExtractedData(result);
      setStatus('success');
    } catch (err: any) {
      console.error("Extraction error:", err);
      setError(err.message || "An unexpected error occurred during extraction.");
      setStatus('error');
    }
  };

  const resetApp = () => {
    setStatus('idle');
    setError(null);
    setExtractedData(null);
    setFileInfo(null);
  };

  return (
    <div className="min-h-screen bg-zinc-950 flex flex-col">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-zinc-950/80 backdrop-blur-md border-b border-zinc-800">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
            </div>
            <div>
              <h1 className="text-lg font-bold text-white leading-tight">InvoiceLens AI</h1>
              <p className="text-xs text-zinc-500 font-medium">Gemini 3 Powered Extraction</p>
            </div>
          </div>

          {extractedData && (
            <button 
              onClick={resetApp}
              className="px-4 py-2 text-sm font-medium text-zinc-400 hover:text-white transition-colors"
            >
              Start New Extraction
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow max-w-7xl mx-auto w-full px-4 py-12">
        {status === 'idle' || status === 'error' ? (
          <div className="max-w-3xl mx-auto">
            <div className="text-center mb-12">
              <h2 className="text-4xl font-extrabold text-white mb-4 tracking-tight">Turn Invoices into Insights.</h2>
              <p className="text-xl text-zinc-400">
                Upload your invoices as PDF, image, or text. Our AI will automatically extract every detail into structured JSON format in seconds.
              </p>
            </div>

            {error && (
              <div className="mb-8 p-4 bg-red-500/10 border border-red-500/20 rounded-xl flex items-start gap-3">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-500 mt-0.5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
                </svg>
                <div>
                  <h3 className="text-red-500 font-semibold text-sm">Extraction Failed</h3>
                  <p className="text-red-400/80 text-sm mt-1">{error}</p>
                </div>
              </div>
            )}

            <FileUpload onFileSelect={handleFileSelect} isLoading={status === 'processing'} />

            {/* Features Info */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-16">
              {[
                { title: 'Multimodal AI', desc: 'Processes PDF, JPEG, PNG, and plain text documents seamlessly.', icon: '🧠' },
                { title: 'Smart Extraction', desc: 'Identifies line items, tax, vendor info, and payment terms accurately.', icon: '✨' },
                { title: 'Developer Ready', desc: 'Get perfectly validated JSON output for your apps and databases.', icon: '🛠️' },
              ].map((f, i) => (
                <div key={i} className="p-6 rounded-2xl bg-zinc-900/40 border border-zinc-800/50">
                  <div className="text-3xl mb-4">{f.icon}</div>
                  <h3 className="text-white font-semibold mb-2">{f.title}</h3>
                  <p className="text-zinc-500 text-sm leading-relaxed">{f.desc}</p>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            {/* Sidebar / File Info */}
            <div className="lg:col-span-4 space-y-6">
              <div className="bg-zinc-900 rounded-2xl p-6 border border-zinc-800">
                <h3 className="text-white font-bold mb-4 flex items-center gap-2">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-indigo-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                  </svg>
                  Document Info
                </h3>
                {fileInfo && (
                  <div className="space-y-4">
                    <div className="flex flex-col gap-1">
                      <span className="text-zinc-500 text-xs font-semibold uppercase">Filename</span>
                      <span className="text-zinc-300 font-medium truncate">{fileInfo.name}</span>
                    </div>
                    <div className="flex flex-col gap-1">
                      <span className="text-zinc-500 text-xs font-semibold uppercase">Size / Type</span>
                      <span className="text-zinc-300 font-medium">{fileInfo.size} • {fileInfo.type.split('/')[1]?.toUpperCase() || 'TEXT'}</span>
                    </div>
                    {fileInfo.previewUrl && (
                      <div className="mt-4 pt-4 border-t border-zinc-800">
                        <span className="text-zinc-500 text-xs font-semibold uppercase block mb-2">Preview</span>
                        <div className="rounded-xl overflow-hidden border border-zinc-800 aspect-square">
                          <img src={fileInfo.previewUrl} alt="Preview" className="w-full h-full object-cover" />
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </div>

              <div className="bg-gradient-to-br from-indigo-900/20 to-zinc-900 rounded-2xl p-6 border border-indigo-500/20">
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-8 h-8 rounded-full bg-indigo-500/20 flex items-center justify-center">
                    <span className="text-indigo-400 text-lg">💡</span>
                  </div>
                  <h4 className="text-white font-semibold">Pro Tip</h4>
                </div>
                <p className="text-zinc-400 text-sm leading-relaxed">
                  The JSON data is perfectly structured according to standard accounting schemas. You can directly import this into systems like Quickbooks, Xero, or custom databases.
                </p>
              </div>
            </div>

            {/* Results Display */}
            <div className="lg:col-span-8 flex flex-col min-h-[600px]">
              <div className="flex items-center justify-between mb-4 bg-zinc-900 p-1.5 rounded-xl border border-zinc-800 self-start">
                <button
                  onClick={() => setViewMode('visual')}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${viewMode === 'visual' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-zinc-400 hover:text-white'}`}
                >
                  Visual Summary
                </button>
                <button
                  onClick={() => setViewMode('json')}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${viewMode === 'json' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-zinc-400 hover:text-white'}`}
                >
                  Raw JSON
                </button>
              </div>

              <div className="flex-grow">
                {extractedData && (
                  viewMode === 'visual' ? (
                    <div className="bg-zinc-900 rounded-2xl p-8 border border-zinc-800 animate-in fade-in slide-in-from-bottom-4 duration-500">
                      <InvoiceSummary data={extractedData} />
                    </div>
                  ) : (
                    <div className="h-full animate-in fade-in slide-in-from-bottom-4 duration-500">
                      <JsonDisplay data={extractedData} />
                    </div>
                  )
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="border-t border-zinc-900 py-8 bg-zinc-950">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center justify-between gap-4">
          <p className="text-zinc-500 text-sm">
            © 2024 InvoiceLens AI. Built with Google Gemini API.
          </p>
          <div className="flex gap-6">
            <a href="#" className="text-zinc-500 hover:text-zinc-300 transition-colors text-sm">Privacy Policy</a>
            <a href="#" className="text-zinc-500 hover:text-zinc-300 transition-colors text-sm">API Docs</a>
            <a href="#" className="text-zinc-500 hover:text-zinc-300 transition-colors text-sm">Status</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;
